const __pageData = JSON.parse('{"title":"可访问性理论：包容式设计模型","description":"从社会模型与医学模型的哲学分野出发，系统阐述WCAG 2.2四大原则与三级一致性，深入辅助技术工作原理与认知可访问性，映射到ARIA、键盘导航、色彩对比度及前端可访问性工具链的完整工程实践","frontmatter":{"title":"可访问性理论：包容式设计模型","description":"从社会模型与医学模型的哲学分野出发，系统阐述WCAG 2.2四大原则与三级一致性，深入辅助技术工作原理与认知可访问性，映射到ARIA、键盘导航、色彩对比度及前端可访问性工具链的完整工程实践","date":"2026-05-01T00:00:00.000Z","tags":["UI原理","可访问性","A11y","WCAG","ARIA","包容式设计","屏幕阅读器"],"category":"theoretical-foundations"},"headers":[],"relativePath":"ui-principles/08-accessibility-theory.md","filePath":"ui-principles/08-accessibility-theory.md","lastUpdated":1777715369000}');
